pages.body:
body {
	background: #334451;
	color: white;
	font-family: "Work Sans",sans-serif;
	font-size: 4vw;
  -webkit-tap-highlight-color: rgba(0,0,0,0);
}

h2 {
  text-align: left;
  font-size: 4vw;
  color: #FFFFFF;
  z-index: 4;
}
p {
	color: #FFFFFF;
	font-size: 4vw;
	
}
a {
	color: #FFFFFF;
	text-decoration: none;
}

.spacer {
	margin-top: 3vw;
	width: 100%;
}

.topbar {
	margin-left: 10px;
	margin-right: 10px;
}

.topspace {
	height: 5vh;
}
.topicon {
	height: 8vw;
	cursor: pointer;
}

.topicon:active {
  background: #d0d0d03f;
}

.toptitle {
	position: static;
	width: 100%;
  	text-align: center;
	margin-top: -30px;
}


.isetting {
	display: inline-block;
	width: 80%;
	margin-top: 2%;
	margin-left: 12%;
	color: white;
}

.setting {
  display: inline-block;
  position: relative;
  width: 98%;
  margin: 1%;  
  padding-bottom: 1vh;
  color: white;

}

.darkbutton {
  border-radius: 5px;
  font-size: 80%;
  padding: 2vw;
  text-align: center;
  background: #46525e;
  cursor: pointer;
}

.disable-click {
  position: absolute;
  top: calc(8vw + 8px);
  left: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  z-index: 10;
}

.enable-click {
  position: fixed;
  top: 0;
  left: 0;
  width: 0%;
  height: 0%;
  opacity: 0;
  z-index: -1;
}

.reconnectPopupDiv {
	display: none;
	justify-content: center;
	align-items: center;
	background-color: #334451;
	color: white;
	border-radius: 16px;
	border: 2px solid #AAAAAA;
	position: fixed;
	font-size: 3vw;
	text-align: center;
	top: 30%;
	left: 10%;
	width: 80%;
	height: 40%;
	z-index: 5;
}

.enabledbutton {
	border-radius: 5px;
	font-size: 80%;
	padding: 2vw;
  text-align: center;
  background: #C0C0C0;
  cursor: pointer;
}

.enabledbutton:active {
  background: #d0d0d03f;
}

#colorbar {
	margin-top: 4vh;
	width: 100%;
	margin: auto;
	text-align: center;
}

